// ===== Edit these =====
const BASE_URL = 'http://host.docker.internal:3002';
const USERNAME = 'test';
const PASSWORD = '10086111';

return {
  json: {
    base_url: BASE_URL.replace(/\/+$/, ''),
    username: USERNAME,
    password: PASSWORD
  }
};

const all = $input.all();

// Parse check-status result
const statusCheck = all.find(item => item.json && item.json.hasOwnProperty('success') && !item.json.hasOwnProperty('login_success')) || all[0];
const statusRes = statusCheck ? statusCheck.json : {};

// Parse login result
const loginAll = all.filter(item => {
  const j = item.json || {};
  return j.success !== undefined && (j.data || j.message === 'Username or password');
});

// Actually, simpler: item 0 = status check, item 1+ = login
const body = all[1] ? all[1].json : (all[0] ? all[0].json : {});

// Extract session cookie
let setCookie = '';
if (all.length > 1 && all[1].json) {
  // Headers might be in different places
  for (let i = 1; i < all.length; i++) {
    const h = all[i].json;
    if (h && h.headers && h.headers['set-cookie']) { setCookie = h.headers['set-cookie']; break; }
    if (h && h['set-cookie']) { setCookie = h['set-cookie']; break; }
  }
}
if (!setCookie && all[0] && all[0].headers && all[0].headers['set-cookie']) {
  setCookie = all[0].headers['set-cookie'];
}

const cm = setCookie.match(/(session=[^;]+)/);
const sessionCookie = cm ? cm[1] : '';

const loginOk = body.success === true;
const user = body.data || {};

return {
  json: {
    connectivity: {
      status: statusRes.success ? 'OK' : 'FAIL',
      server_version: statusRes.data?.version || statusRes.message || 'unknown',
      raw: statusRes
    },
    login: {
      status: loginOk ? 'SUCCESS' : 'FAILED',
      message: body.message || '',
      user: loginOk ? {
        id: user.id,
        username: user.username,
        display_name: user.display_name,
        role: user.role,
        status: user.status === 1 ? 'enabled' : 'disabled',
        group: user.group
      } : null,
      auth: loginOk ? {
        session_cookie: sessionCookie ? sessionCookie.substring(0, 30) + '...' : '(not found)',
        new_api_user_header: user.id || 'N/A',
        note: 'Send: Cookie: session=... AND New-Api-User: ' + (user.id || 'N/A')
      } : null
    },
    debug: {
      base_url_used: $('config').first().json.base_url,
      username_used: $('config').first().json.username,
      login_raw_body: body
    }
  }
};
